@implementation JUNRouteBuilder

- (NSMutableArray<JUNRouteModel *> *)routes {
    if (_routes == nil) {
        _routes = [NSMutableArray array];
    }
    return _routes;
}

- (void)name:(NSString *)name handle:(void (^)(NSDictionary * _Nullable, void (^ _Nonnull)(id<JUNRouter> _Nonnull)))handler {
