- (void)jun_routeHandle:(NSURL *)url cursor:(int *)cursor nextHandler:(JUNRouterNextHandler)next {
    NSOperationQueue *queue = [NSOperationQueue currentQueue];
    JUNRouterNextHandler wrappedNext = ^(id<JUNRouter> _Nullable dest) {
