    if ([[prevRouter class] isEqual:[nextRouter class]]) {
        wrappedNext(nextRouter);
        return;
    }
    dispatch_async(dispatch_get_main_queue(), ^{
        [self _handleTransitionFrom:prevRouter to:nextRouter nextHandler:wrappedNext];
    });
}

