@interface WBCustomPopupViewController ()

@property (strong, nonatomic) UIImageView *imageView;
@property (strong, nonatomic) UIImage *mainImage;
@property (strong, nonatomic) UIButton *closeButton;
@property (copy, nonatomic) NSArray *buttonData;
@property (strong, nonatomic) NSArray<UIButton *> *tapButtons;

@end

@implementation WBCustomPopupViewController

#pragma mark - Initialization

- (instancetype)initWithImageName:(UIImage *)image linkURL:(NSString *)linkURL richMessageLinkId:(NSString *)richMessageLinkId linkType:(NSString *)linkType dismiss:(NSString *)dismiss buttonData:buttonData{
    self = [super initWithNibName:nil bundle:nil];
    if (self) {
        self.mainImage = image;     // 弹窗主图
        self.linkURL = linkURL;     // 活动弹窗跳转链接
        self.richMessageLinkId = richMessageLinkId;
        self.linkType = linkType;   // 活动链接的跳转类型
        self.dismiss = dismiss;     // 活动弹窗是否关闭
        self.buttonData = buttonData;
        [self setupUI];
    }
    return self;
}

#pragma mark - View Lifecycle

- (void)viewDidLoad {
    [super viewDidLoad];
    self.view.backgroundColor = [UIColor colorWithWhite:0 alpha:0.8]; // 透明黑色背景
}

#pragma mark - Setup UI

- (void)setupUI {
    [self generateTapButtons];   // 在添加视图之前生成按钮
    [self addSubviews];          // 添加所有子视图
    [self addAllConstraints];    // 添加约束
    [self addGestures];          // 添加手势
    [self setupCloseButton];     // 设置关闭按钮

    if (self.mainImage) {
        self.imageView.image = self.mainImage;
    }
}

- (void)addSubviews {
    [self.view addSubview:self.imageView];
    [self.view addSubview:self.closeButton];

    // 确保按钮已经被正确创建并添加到视图中
    for (UIButton *button in self.tapButtons) {
        [self.view addSubview:button];
    }

    // 调用布局方法来设置按钮位置
    [self layoutTapButtons];
}


- (void)addAllConstraints {
    CGFloat aspectRatio = self.mainImage.size.height / self.mainImage.size.width;
    [self.imageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.centerX.equalTo(self.view);
        if (self.buttonData.count >= 1) {
            make.centerY.equalTo(self.view).offset(ZOOM(-30));
        } else {
            make.centerY.equalTo(self.view);
        }
        make.width.mas_equalTo(ZOOM(301));
        make.height.mas_equalTo(ZOOM(301) * aspectRatio);
    }];

    [self.closeButton mas_makeConstraints:^(MASConstraintMaker *make) {
        make.right.equalTo(self.imageView.mas_right);
        make.top.equalTo(self.imageView.mas_top);
        make.width.height.mas_equalTo(ZOOM(24));
    }];

}

- (void)addGestures {
    UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(imageTapped:)];
    tapGesture.numberOfTapsRequired = 1;
    tapGesture.cancelsTouchesInView = NO;
    [self.imageView addGestureRecognizer:tapGesture];
    self.imageView.userInteractionEnabled = YES;
}

- (void)setupCloseButton {
    [self.closeButton setBackgroundImage:[UIImage imageNamed:@"退出_icon"] forState:UIControlStateNormal];
    [self.closeButton addTarget:self action:@selector(dismissPopup) forControlEvents:UIControlEventTouchUpInside];
}


#pragma mark - Actions

- (void)imageTapped:(UITapGestureRecognizer *)gestureRecognizer {
    [self handleTapEventForButtonAtIndex:-1];  // -1 用于表示图片点击
}

- (void)buttonClicked:(UIButton *)button {
    // 获取按钮的索引，统一处理点击事件
    NSInteger index = button.tag;
    [self handleTapEventForButtonAtIndex:index];  // 传递按钮的索引
}

- (void)handleTapEventForButtonAtIndex:(NSInteger)index {
    NSString *link = nil;
    NSString *linkType = nil;
    NSString *dismiss = nil;
    NSString *richMessageLinkId = nil;

    if (index == -1) {
        // 图片被点击，使用全局的 linkURL 和 linkType
        link = self.linkURL;
        richMessageLinkId = self.richMessageLinkId;
        linkType = self.linkType;
        dismiss = self.dismiss;
    } else {
        // 按钮被点击，使用该按钮的数据
        if (index < self.buttonData.count) {
            NSDictionary *data = self.buttonData[index];
            link = data[@"link"];
            richMessageLinkId = [data[@"id"] stringValue];
